const item = $input.first().json;

function fixMojibake(s = "") {
  s = String(s);
  if (!/(Ã.|Â.|â€™|â€œ|â€|�)/.test(s)) return s;

  try {
    const bytes = Uint8Array.from(s, c => c.charCodeAt(0) & 0xff);
    const decoded = new TextDecoder("utf-8", { fatal: false }).decode(bytes);
    return decoded;
  } catch (e) {
    return s;
  }
}

function decodeLatinEntities(s = "") {
  return s
    .replace(/&aacute;/gi, "á")
    .replace(/&eacute;/gi, "é")
    .replace(/&iacute;/gi, "í")
    .replace(/&oacute;/gi, "ó")
    .replace(/&uacute;/gi, "ú")
    .replace(/&ntilde;/gi, "ñ")
    .replace(/&uuml;/gi, "ü")
    .replace(/&ccedil;/gi, "ç")
    .replace(/&Aacute;/g, "Á")
    .replace(/&Eacute;/g, "É")
    .replace(/&Iacute;/g, "Í")
    .replace(/&Oacute;/g, "Ó")
    .replace(/&Uacute;/g, "Ú")
    .replace(/&Ntilde;/g, "Ñ");
}

function htmlToText(s) {
  return String(s)
    .replace(/<br\s*\/?>/gi, "\n")
    .replace(/<\/p>/gi, "\n")
    .replace(/<[^>]+>/g, "")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&#39;/g, "'")
    .replace(/&quot;/g, '"');
}

const subject = fixMojibake(item.subject || "");
const subjectLower = subject.toLowerCase();
const isLead =
  subjectLower.includes("nuevo mensaje de contacto") ||
  subjectLower.includes("mensaje de contacto") ||
  subjectLower.includes("contacto");

if (!isLead) {
  return [{ ...item, isLead: false, reason: "Not lead", source_kind: "email" }];
}

const textHtml = decodeLatinEntities(fixMojibake(item.textHtml || ""));
const textPlain = decodeLatinEntities(fixMojibake(item.textPlain || ""));
const text = textHtml ? htmlToText(textHtml) : textPlain;

function pick(re) {
  const m = text.match(re);
  return m ? m[1].trim() : "";
}

const nombre = pick(/Nombre:\s*(.+)/i);
const apellidos = pick(/Apellidos:\s*(.+)/i);
const email = pick(/Email:\s*([^\s]+)/i);
const telefono = pick(/Tel[eé]fono:\s*([0-9+\s-]+)/i);
const mensaje = pick(/Mensaje:\s*([\s\S]+)/i);

const fullName = [nombre, apellidos].filter(Boolean).join(" ").trim() || nombre || "Lead";

return [{
  isLead: true,
  source_kind: "email",
  subject,
  body: {
    name: fullName,
    email,
    phone: telefono,
    message: mensaje,
  }
}];

const msg = ($input.first().json.body?.message || "").toLowerCase();

let score = 0;

const hasAny = (arr) => arr.some(w => msg.includes(w));

if (hasAny(["urgente","esta semana","mañana","ya","cuanto antes"])) score += 3;
if (hasAny(["demo","llamada","reunión","reunion","agendar","calendario"])) score += 3;
if (hasAny(["presupuesto","precio","coste","costo","tarifa","cuánto","cuanto"])) score += 2;
if (hasAny(["crm","whatsapp","zapier","hubspot","pipeline","automatizar","integración","integracion"])) score += 1;
if (msg.length < 20) score -= 1;

let temperature = "cold";
if (score >= 5) temperature = "hot";
else if (score >= 2) temperature = "warm";

const confidence = Math.max(0.4, Math.min(0.95, 0.5 + score * 0.08));

return [{
  ...$input.first().json,
  source_kind: $input.first().json.source_kind ?? "web",
  lead: {
    name: $input.first().json.body?.name,
    email: $input.first().json.body?.email,
    message: $input.first().json.body?.message,
  },
  scoring: {
    score,
    temperature,
    confidence: Number(confidence.toFixed(2)),
  }
}];

const item = $input.first().json;

// reply completo del modelo (HTML o texto)
const reply = (item.reply || "").trim();

// intent detectado previamente (meeting | budget | info | etc.)
const intent = (item.intent || "").toLowerCase();

// 1️⃣ Subject por intent (fallback)
let subjectByIntent = "Tech & Investments";

switch (intent) {
  case "meeting":
    subjectByIntent = "Coordinemos una reunión sobre automatización";
    break;
  case "budget":
    subjectByIntent = "Propuesta y presupuesto de automatización";
    break;
  case "info":
    subjectByIntent = "Información sobre soluciones de automatización";
    break;
}

// 2️⃣ Subject final
let subject = subjectByIntent;
let body = reply;

// 3️⃣ Si la IA devuelve "Asunto: xxx", tiene prioridad
const m = reply.match(/^Asunto:\s*(.+)\n+/i);
if (m) {
  subject = m[1].trim();
  body = reply.replace(/^Asunto:\s*.+\n+/i, "").trim();
}

// 4️⃣ Destinatario
const to = item.email;

// 5️⃣ Salida para Gmail
return [{
  json: {
    email_to: to,
    email_subject: subject,
    email_body: body, // HTML generado por la IA
  }
}];

const item = $input.first().json;

function pick(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== '') {
      return value;
    }
  }
  return null;
}

function buildUtmFields(sourceKind, payload = item) {
  const serviceSlug = pick(payload.service_slug, payload.serviceSlug, payload.playbook, payload.recommended_service);
  const isInboundWeb = sourceKind === 'web' || sourceKind === 'email' || sourceKind === 'whatsapp';
  return {
    serviceSlug,
    utmSource: pick(payload.utmSource, payload.utm_source, isInboundWeb ? 'tech_investments' : 'lead_ops'),
    utmMedium: pick(payload.utmMedium, payload.utm_medium, isInboundWeb ? sourceKind : 'automation'),
    utmCampaign: pick(payload.utmCampaign, payload.utm_campaign, isInboundWeb ? 'tech_investments_inbound' : 'lead_ops_to_crm'),
    utmTerm: pick(payload.utmTerm, payload.utm_term, serviceSlug),
    utmContent: pick(payload.utmContent, payload.utm_content, sourceKind),
  };
}

function buildWebOrEmailPayload(sourceKind) {
  const iaNotes = {
    origin: sourceKind,
    name: item.name ?? null,
    email: item.email ?? null,
    message: item.message ?? null,
    reply: item.reply ?? null,
    intent: item.intent ?? null,
    temperature: item.temperature ?? null,
    confidence: item.confidence ?? null,
    subject: item.subject ?? null,
  };
  const utm = buildUtmFields(sourceKind);

  return {
    email: item.email,
    name: item.name,
    company: item.company ?? null,
    phone: item.phone ?? null,
    website: item.website ?? null,
    message: item.message ?? null,
    notes: null,
    iaNotes: JSON.stringify(iaNotes),
    temperature: item.temperature ?? 'cold',
    intent: item.intent ?? 'info',
    source: sourceKind,
    ...utm,
    estimatedValue: null,
    nextActionAt: null,
    lostReason: null,
    serviceIds: [],
  };
}

function buildWhatsAppPayload(sourceKind) {
  const inbound = item.body && typeof item.body === 'object' ? item.body : item;
  const waId = pick(inbound.wa_id, inbound.waId, inbound.sender, inbound.from);
  const contactName = pick(inbound.contact_name, inbound.contactName, inbound.name, inbound.profile?.name);
  const messageText = pick(inbound.text, inbound.message, inbound.body, inbound.message_text);
  const email = pick(
    inbound.email,
    inbound.contact?.email,
    waId ? 'wa-' + String(waId).replace(/[^a-zA-Z0-9]/g, '') + '@whatsapp.local' : null,
  );
  const name = pick(contactName, waId, 'WhatsApp Lead');
  const phone = pick(inbound.phone, inbound.sender, inbound.from, waId);
  const iaNotes = {
    origin: sourceKind,
    waId,
    sender: inbound.sender ?? null,
    contactName,
    messageId: inbound.message_id ?? inbound.messageId ?? null,
    message: messageText ?? null,
  };
  const utm = buildUtmFields(sourceKind, inbound);

  return {
    email,
    name,
    company: null,
    phone,
    website: null,
    message: messageText ?? null,
    notes: null,
    iaNotes: JSON.stringify(iaNotes),
    temperature: 'warm',
    intent: 'info',
    source: sourceKind,
    ...utm,
    estimatedValue: null,
    nextActionAt: null,
    lostReason: null,
    serviceIds: [],
  };
}

function mergeCrmPayload(sourceKind, payload) {
  const utm = buildUtmFields(sourceKind, { ...item, ...payload });
  return {
    ...payload,
    ...utm,
  };
}

const sourceKindRaw = item.source_kind || item.body?.source_kind || item.source || item.body?.source || item.channel || item.body?.channel || item.provider || item.body?.provider || 'web';
const sourceKind = sourceKindRaw === 'whatsapp_cloud_api' ? 'whatsapp' : sourceKindRaw;
const inboundPayload = item.body?.crm_payload ?? item.crm_payload;
if (inboundPayload && typeof inboundPayload === 'object') {
  return [{ json: { ...item, crm_payload: mergeCrmPayload(sourceKind, inboundPayload) } }];
}

if (sourceKind === 'whatsapp') {
  return [{
    json: {
      ...item,
      crm_payload: buildWhatsAppPayload(sourceKind),
    }
  }];
}

return [{
  json: {
    ...item,
    crm_payload: buildWebOrEmailPayload(sourceKind),
  }
}];
